using sv_81715c0ae3db4a1292caba3bb44c7678.Models;

namespace sv_81715c0ae3db4a1292caba3bb44c7678.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato sauce, mozzarella, and fresh basil.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino romano.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
            new(4, "Risotto alla Milanese", "Saffron-infused risotto with parmesan cheese.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Chicken Tikka Masala", "Tender chicken in a creamy spiced tomato sauce.", 50),
            new(6, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(7, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
            new(8, "Samosa", "Crispy pastry filled with spiced potatoes and peas.", 55),
        },
        [3] = new List<Recipe>
        {
            new(9, "Kung Pao Chicken", "Stir-fried chicken with peanuts, vegetables, and chili peppers.", 30),
            new(10, "Mapo Tofu", "Silken tofu in a spicy, numbing sauce with ground pork.", 25),
            new(11, "Char Siu", "Cantonese-style barbecued pork with a sweet glaze.", 90),
            new(12, "Hot and Sour Soup", "Tangy and spicy soup with tofu, mushrooms, and bamboo shoots.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return RecipesByCuisine.TryGetValue(cuisineId, out var recipes)
            ? new List<Recipe>(recipes)
            : new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@using sv_81715c0ae3db4a1292caba3bb44c7678.Models
@using sv_81715c0ae3db4a1292caba3bb44c7678.Services
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (displayedRecipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    @if (displayedRecipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Description</th>
                    <th>Prep Time (min)</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var recipe in SortedRecipes)
                {
                    <tr>
                        <td>@recipe.Title</td>
                        <td>@recipe.Description</td>
                        <td>@recipe.PrepTimeMinutes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? displayedRecipes;
    private bool isRefreshing;
    private string? errorMessage;

    private int loadedCuisineId;
    private CancellationTokenSource? loadCts;
    private readonly CancellationTokenSource disposeCts = new();

    private IEnumerable<Recipe> SortedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => displayedRecipes!.OrderByDescending(r => r.Id),
            "popular" => displayedRecipes!.OrderByDescending(r => r.PrepTimeMinutes),
            _ => displayedRecipes!
        };

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        // Sort-only change: no reload needed, the property is already updated.
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for the previous cuisine.
        if (loadCts is not null)
        {
            await loadCts.CancelAsync();
            loadCts.Dispose();
        }

        loadCts = CancellationTokenSource.CreateLinkedTokenSource(disposeCts.Token);
        var cts = loadCts;
        var cuisineId = CuisineId;

        isRefreshing = displayedRecipes is not null;
        errorMessage = null;

        try
        {
            var recipes = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            displayedRecipes = recipes;
            loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected: the user navigated to another cuisine or left the page.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        disposeCts.Cancel();
        disposeCts.Dispose();
        loadCts?.Dispose();
    }
}

